#include <bits/stdc++.h>
using namespace std;
const int N=1e5+1;
int n,a[30004],c[N],l[30004],r[30004];
long long ans=0;
int Lowbit(int x){
    int cnt=0;
    while(!(x&1))
        x>>=1,cnt++;
    return 1<<cnt;
}
void Plus(int a,int b){
    if(a>N)
        return;
    c[a]+=b;
    Plus(a+Lowbit(a),b);
}
int Sum(int a){
	if(a<1)
		return 0;
	return c[a]+Sum(a-Lowbit(a));
}
int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++){
        scanf("%d",&a[i]);
        Plus(a[i],1);
        l[i]=Sum(a[i]-1);
    }
    memset(c,0,sizeof(c));
    for(int i=n;i;i--){
        Plus(a[i],1);
        r[i]=(n-i+1)-Sum(a[i]);
        ans+=1LL*l[i]*r[i];
    }
    cout<<ans;
    return 0;
}
